// 配置源商品链接和目标平台
const sourceUrl = $input.first().json.sourceUrl || 'https://item.taobao.com/item.htm?id=xxxx';
const sourcePlatform = $input.first().json.sourcePlatform || 'taobao';
const targetPlatforms = $input.first().json.targetPlatforms || ['pdd', 'douyin'];

return [{
  json: {
    sourceUrl,
    sourcePlatform,
    targetPlatforms,
    timestamp: new Date().toISOString()
  }
}];

// 解析HTML提取商品信息
const cheerio = require('cheerio');
const $ = cheerio.load($input.first().json.data);

// 提取标题
let title = $('h1[data-spm="title"]').text() || 
            $('.tb-detail-hd h1').text() || 
            '[data-testid="pdp-title"]').text() ||
            '未获取到标题';

// 提取价格
let priceText = $('.tb-rmb-num').first().text() || 
                $('.notranslate').first().text() ||
                '[class*="price"]').first().text() ||
                '0';
let price = parseFloat(priceText.replace(/[¥,]/g, '')) || 0;

// 提取主图
let images = [];
$('#J_UlThumb img').each((i, el) => {
  let src = $(el).attr('src');
  if (src) images.push(src.replace(/_\d+x\d+.*\./, '.'));
});

// 提取详情图
let detailImages = [];
$('.J_DetailContent img').each((i, el) => {
  let src = $(el).attr('src');
  if (src) detailImages.push(src);
});

return [{
  json: {
    title: title.trim().substring(0, 60),
    price: price,
    originalPrice: Math.round(price * 1.2 * 100) / 100,
    stock: 999,
    images: images.slice(0, 5),
    detailImages: detailImages.slice(0, 10),
    description: title.trim(),
    sourceUrl: $input.first().json.sourceUrl,
    sourcePlatform: $input.first().json.sourcePlatform
  }
}];

// 处理图片：下载、加水印、压缩
const product = $input.first().json;
const processedImages = [];

for (let imgUrl of product.images) {
  // 构建图片处理任务
  processedImages.push({
    url: imgUrl,
    filename: 'img_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9) + '.jpg',
    watermark: '你的店铺名'
  });
}

return processedImages.map((img, i) => ({
  json: {
    ...img,
    index: i,
    productTitle: product.title
  }
}));

// 这里可以调用图片处理API
// 例如：remove.bg去背景、加水印、压缩等

const imageData = $input.first().json.data;
const watermark = $input.first().json.watermark;

// 构建处理后的图片信息
return [{
  json: {
    originalUrl: $input.first().json.url,
    filename: $input.first().json.filename,
    processed: true,
    watermark: watermark,
    size: imageData ? imageData.length : 0
  }
}];

// 构建各平台发布数据
const product = $input.first().json;
const platforms = ['pdd', 'douyin', 'taobao'];

return platforms.map(platform => ({
  json: {
    platform: platform,
    title: platform === 'pdd' ? product.title.substring(0, 30) : product.title.substring(0, 60),
    price: product.price,
    stock: product.stock,
    images: product.images,
    description: product.description,
    ready: true
  }
}));

// 拼多多发布逻辑
// 调用拼多多开放平台API或模拟浏览器操作

const product = $input.first().json;
console.log('发布到拼多多:', product.title);

// 实际实现需要：
// 1. 调用 pdd.goods.add API
// 2. 或使用puppeteer/playwright模拟发布

return [{
  json: {
    platform: 'pdd',
    status: 'published',
    productId: 'PDD_' + Date.now(),
    title: product.title,
    price: product.price
  }
}];

// 抖音发布逻辑

const product = $input.first().json;
console.log('发布到抖音:', product.title);

return [{
  json: {
    platform: 'douyin',
    status: 'published',
    productId: 'DY_' + Date.now(),
    title: product.title,
    price: product.price
  }
}];

// 淘宝发布逻辑

const product = $input.first().json;
console.log('发布到淘宝:', product.title);

return [{
  json: {
    platform: 'taobao',
    status: 'published',
    productId: 'TB_' + Date.now(),
    title: product.title,
    price: product.price
  }
}];

// 发送通知
const results = $input.all();
const summary = results.map(r => 
  `${r.json.platform}: ${r.json.status} (ID: ${r.json.productId})`
).join('\n');

return [{
  json: {
    message: '铺货完成！\n' + summary,
    timestamp: new Date().toISOString(),
    totalPlatforms: results.length
  }
}];
